INSERT INTO public.products (id, name, description, stock_quantity, price, category_id, image_url, weight, length, width, height, origin_zip, is_active) VALUES (gen_random_uuid(), 'Travesseiro terapêutico HAIFLEX', 'Características<br/><br/>Os travesseiros são firmes e confeccionados com espuma perfilada terapêutica auto massageadora. Possibilita uma massagem que relaxa a musculatura dos ombros e pescoço, aliviando tensões e melhorando a circulação. Une o Infravermelho Longo, tecnologia que simula as características mais benéficas dos raios solares, e a Magnetoterapia, uma terapia natural que oferece inúmeros benefícios ao organismo.<br/><br/>Anti alérgica, anti ácaros e anti fungos.<br/><br/>&nbsp;<br/><br/>Os principais benefícios<br/><br/>* Atua no alinhamento da coluna cervical<br/><br/>* Alivia dores nas costas<br/><br/>* Melhora a circulação e oxigenação sanguínea, induzindo a um sono profundo e reparador<br/><br/>* Favorece o controle da pressão arterial, ajuda a prevenir doenças cardiovasculares<br/><br/>* Aumenta a imunidade do organismo, além de possuir ação analgésica sobre dores do corpo<br/><br/>* Melhora a enxaqueca<br/><br/>* Previne o estresse<br/><br/>* Possui ação anti-inflamatória, sendo ideal desde o alívio de febres até a recuperação pós-operatória', 0, 235.0, NULL, 'https://classeafaria.com.br/wp-content/uploads/sites/7538/2025/08/10.jpg', 0, 0, 0, 0, '82820-160', true);
INSERT INTO public.products (id, name, description, stock_quantity, price, category_id, image_url, weight, length, width, height, origin_zip, is_active) VALUES (gen_random_uuid(), 'Sapato social masculino com Couro Bovino', 'Sapato social masculino feito à mão em couro bovino.<br/><br/>Croco preto.<br/><br/>Possui sola em PU ou seja, solado de poliuretano (PU) . Um material de ótima qualidade e que oferece proteção e conforto, bastante resistente e duradouro', 0, 340.0, NULL, 'https://classeafaria.com.br/wp-content/uploads/sites/7538/2025/08/5.jpg', 0, 0, 0, 0, '82820-160', true);
INSERT INTO public.products (id, name, description, stock_quantity, price, category_id, image_url, weight, length, width, height, origin_zip, is_active) VALUES (gen_random_uuid(), 'Camisa manga longa slim fit button down xadrez', '° Camisa manga longa slim fit button down xadrez<br/><br/>° Azul com Branco<br/><br/>° Ref: 11010120153570<br/><br/>&nbsp;<br/><br/>° Camisa manga longa modelagem SLIM FIT, levemente ajustada ao corpo.<br/><br/>° Puro algodão fio 60, colarinho BUTTON DOWN<br/><br/>° Clássica e atemporal.<br/><br/>° Composição: 100% Algodão', 0, 219.0, NULL, 'https://classeafaria.com.br/wp-content/uploads/sites/7538/2025/08/4.jpg', 0, 0, 0, 0, '82820-160', true);
INSERT INTO public.products (id, name, description, stock_quantity, price, category_id, image_url, weight, length, width, height, origin_zip, is_active) VALUES (gen_random_uuid(), 'Camisa Polo modal', 'A polo modal tem padronagem bicolor, com pontos sutis e elegância em sua combinação de cores.<br/><br/>Composição: 84% Modal e 16% Elastano.', 0, 176.0, NULL, 'https://classeafaria.com.br/wp-content/uploads/sites/7538/2025/08/3.jpg', 0, 0, 0, 0, '82820-160', true);
INSERT INTO public.products (id, name, description, stock_quantity, price, category_id, image_url, weight, length, width, height, origin_zip, is_active) VALUES (gen_random_uuid(), 'Colçhão CLASSIC', 'COLCHÃO CLASSIC<br/><br/>Terapias disponíveis no Colchão Classic<br/><br/>* COLCHÃO ELÉTRICO COM 34 CM ALTURA, TAMPO EM MALHA 400G, CONFORTO EXTRA FIRME.<br/><br/>* ESPUMA PERFILADA DENSIDADE 40, PASTILHADA COM IMÃS E INFRA VERMELHO LONGO, MAIS LÁTEX E ESPUMA D33 MACIA NO PILOW.<br/><br/>* ESTRUTURA COM BORDA DE ESPUMA E POLIESTIRENO EXPANDIDO (EPS), COM SUPORTE ATÉ 180KG.<br/><br/>* KIT VIBRO MASSAGEM COM 24 ESTÁGIOS E 8 MOTORES, ENERGIA QUÂNTICA E CROMOTERAPIA NO CONTROLE.<br/><br/>* SUPORTE DE PESO - ATÉ 180 KG POR PESSOA', 0, 5980.0, NULL, 'https://classeafaria.com.br/wp-content/uploads/sites/7538/2025/08/1.jpg', 40.0, 1.38, 1.38, 0.34, '82820-160', true);
