INSERT INTO public.products (id, name, description, stock_quantity, price, category_id, image_url, weight, length, width, height, origin_zip, is_active) VALUES (gen_random_uuid(), 'BOX HAIFLEX DE MADEIRA " LUXO " SOLTEIRO', 'Box de Madeira LUXO Solteiro<br/><br/>Medidas 0,88 x 1,88 x 31<br/><br/>O box de madeira proporciona maior conforto, e é ideal para o seu colchão devido à maior resistência e durabilidade. Por possuir uma base totalmente plana não deforma seu colchão.<br/><br/>Características<br/><br/><ul><br/><br/> 	<li>Estrutura 100% eucalipto de reflorestamento</li><br/><br/> 	<li>Tecido em malha especial</li><br/><br/> 	<li>Bordado em fibras</li><br/><br/> 	<li>Acabamento refinado com viés premium</li><br/><br/> 	<li>Superfície com espuma amortecedora</li><br/><br/> 	<li>Tampo em Tnt</li><br/><br/> 	<li>Pés de alumínio (rosqueáveis)</li><br/><br/> 	<li>Rodinhas na parte traseira</li><br/><br/></ul><br/><br/>Cuidados<br/><br/>Como tudo que usamos, o box também requer cuidados. Algumas dicas são importantes para garantir a sua durabilidade:<br/><br/><ul><br/><br/> 	<li>Não o colocar em uso com o plástico da embalagem<br/><br/>• Não colocar objetos pontiagudos ou pesados<br/><br/>• Não saltar sobre o box* Garantia contra defeitos de fabricação</li><br/><br/></ul>', 0, 1518.0, 2, 'https://classeafaria.com.br/wp-content/uploads/sites/7538/2025/08/BOX-LUXO-SOLTEIRO.png', 18.0, 188.0, 88.0, 31.0, '82820-160', true);
