INSERT INTO public.products (id, name, description, stock_quantity, price, category_id, image_url, weight, length, width, height, origin_zip, is_active) VALUES (gen_random_uuid(), 'TRAVESSEIRO POWERCHIP', '&nbsp;<br/><br/><strong>Características </strong><br/><br/>Os travesseiros são firmes e confeccionados com espuma perfilada terapêutica auto massageadora. Possibilita uma massagem que relaxa a musculatura dos ombros e pescoço, aliviando tensões e melhorando a circulação. Une o Infravermelho Longo, tecnologia que simula as características mais benéficas dos raios solares, e a Magnetoterapia, uma terapia natural que oferece inúmeros benefícios ao organismo.<br/><br/>Anti alérgica, anti ácaros e anti fungos.<br/><br/><strong> </strong><br/><br/><strong>Os principais benefícios</strong><br/><br/>• Atua no alinhamento da coluna cervical<br/><br/>• Alivia dores nas costas<br/><br/>• Melhora a circulação e oxigenação sanguínea, induzindo a um sono profundo e reparador<br/><br/>• Favorece o controle da pressão arterial, ajuda a prevenir doenças cardiovasculares<br/><br/>• Aumenta a imunidade do organismo, além de possuir ação analgésica sobre dores do corpo<br/><br/>• Melhora a enxaqueca<br/><br/>• Previne o estresse<br/><br/>• Possui ação anti-inflamatória, sendo ideal desde o alívio de febres até a recuperação pós-operatória', 0, 440.0, 15, 'https://classeafaria.com.br/wp-content/uploads/sites/7538/2025/08/TRAVESSEIRO-POWERCHIP.png', 1.7, 60.0, 34.0, 15.0, '82820-160', true);
INSERT INTO public.products (id, name, description, stock_quantity, price, category_id, image_url, weight, length, width, height, origin_zip, is_active) VALUES (gen_random_uuid(), 'TRAVESSEIRO CONFORT', '<strong>Características </strong><br/><br/>Os travesseiros são firmes e confeccionados com espuma perfilada terapêutica auto massageadora. Possibilita uma massagem que relaxa a musculatura dos ombros e pescoço, aliviando tensões e melhorando a circulação. Une o Infravermelho Longo, tecnologia que simula as características mais benéficas dos raios solares, e a Magnetoterapia, uma terapia natural que oferece inúmeros benefícios ao organismo.<br/><br/>Anti alérgica, anti ácaros e anti fungos.<br/><br/><strong> </strong><br/><br/><strong>Os principais benefícios</strong><br/><br/>• Atua no alinhamento da coluna cervical<br/><br/>• Alivia dores nas costas<br/><br/>• Melhora a circulação e oxigenação sanguínea, induzindo a um sono profundo e reparador<br/><br/>• Favorece o controle da pressão arterial, ajuda a prevenir doenças cardiovasculares<br/><br/>• Aumenta a imunidade do organismo, além de possuir ação analgésica sobre dores do corpo<br/><br/>• Melhora a enxaqueca<br/><br/>• Previne o estresse<br/><br/>• Possui ação anti-inflamatória, sendo ideal desde o alívio de febres até a recuperação pós-operatória<br/><br/>&nbsp;', 0, 235.0, 16, 'https://classeafaria.com.br/wp-content/uploads/sites/7538/2025/08/TRAVESSEIRO-CONFORT-12-CM.png', 1.6, 60.0, 34.0, 12.0, '82820-160', true);
INSERT INTO public.products (id, name, description, stock_quantity, price, category_id, image_url, weight, length, width, height, origin_zip, is_active) VALUES (gen_random_uuid(), 'TRAVESSEIRO LATEX', '<strong>Características </strong><br/><br/>Anti alérgica, anti ácaros e anti fungos.<br/><br/><strong> </strong><br/><br/><strong>Os principais benefícios</strong><br/><br/>• Atua no alinhamento da coluna cervical<br/><br/>• Alivia dores nas costas<br/><br/>• Melhora a circulação e oxigenação sanguínea, induzindo a um sono profundo e reparador<br/><br/>• Favorece o controle da pressão arterial, ajuda a prevenir doenças cardiovasculares<br/><br/>• Aumenta a imunidade do organismo, além de possuir ação analgésica sobre dores do corpo<br/><br/>• Melhora a enxaqueca<br/><br/>• Previne o estresse<br/><br/>• Possui ação anti-inflamatória, sendo ideal desde o alívio de febres até a recuperação pós-operatória<br/><br/>&nbsp;', 0, 340.0, 14, 'https://classeafaria.com.br/wp-content/uploads/sites/7538/2025/08/traveseiro-latex.png', 1.6, 60.0, 34.0, 14.0, '82820-160', true);
INSERT INTO public.products (id, name, description, stock_quantity, price, category_id, image_url, weight, length, width, height, origin_zip, is_active) VALUES (gen_random_uuid(), 'PULCEIRA POWERCHIP', 'O Powerchip®️ metaboliza os íons positivos, tornando-os alcalinos e negativos através de uma frequência saudável para as células, promovendo o equilíbrio da energia vital.<br/><br/><u><strong>Tecnologias:</strong></u><br/><br/>• Nanotecnologia (Ativação Iônica)<br/><br/>Refere-se a um processo de ativação iônica, após ter sido submetido ao campo elétrico, em um processo que aproveita a ação da gravidade, proporciona um fluxo de íons ao mineral e resulta na obtenção da nanotecnologia.<br/><br/>• Infravermelho Longo<br/><br/>A tecnologia com o infravermelho longo é composta por minerais e metais nobres que possibilitam a emissão de ondas eletromagnéticas de 9 a 14 mícrons, semelhantes aos raios do sol emitidos pela manhã e ao final da tarde.<br/><br/>• Energia Quântica<br/><br/>A tecnologia quântica consiste em propagar os pulsos recebidos através da ativação elétrica e iônica que recebeu dos íons negativos que foram gerados através do contato com o calor do corpo.', 0, 0, 36, 'https://classeafaria.com.br/wp-content/uploads/sites/7538/2025/08/PULCEIRA-POWERCHIP.jpeg', 0.5, 15.0, 12.0, 15.0, '82820-160', true);
INSERT INTO public.products (id, name, description, stock_quantity, price, category_id, image_url, weight, length, width, height, origin_zip, is_active) VALUES (gen_random_uuid(), 'Camiseta Estonada Stoned – Básica', '<h3 data-start="147" data-end="206"><strong data-start="151" data-end="206">Camiseta Estonada Stoned – Básica com Personalidade</strong></h3><br/><br/><p data-start="208" data-end="426">Minimalista na forma, única no estilo. A Camiseta Estonada traz o visual desgastado intencional que conquistou o streetwear, sem abrir mão do conforto. Um modelo essencial para homens que curtem simplicidade com atitude.</p><br/><br/><p data-start="433" data-end="459"><strong data-start="433" data-end="459">Diferenciais Técnicos:</strong></p><br/><br/><p data-start="463" data-end="538">100% algodão de alta qualidade, garantindo toque macio e respirabilidade.</p><br/><br/><p data-start="541" data-end="613">Lavagem estonada que confere um visual vintage exclusivo em cada peça.</p><br/><br/><p data-start="616" data-end="708">Gola com acabamento canelado reforçado e costuras aparentes que trazem identidade ao look.</p><br/><br/><p data-start="711" data-end="765">Modelagem reta e confortável, ideal para uso diário.</p><br/><br/><p data-start="772" data-end="802"><strong data-start="772" data-end="802">Usabilidade e Combinações:</strong></p><br/><br/><p data-start="806" data-end="879">Perfeita para usar com jeans, sarja clara ou bermudas para o dia a dia.</p><br/><br/><p data-start="882" data-end="955">Combina com tênis branco, chinelo ou bota casual para diferentes vibes.</p><br/><br/><p data-start="958" data-end="1054">Pode ser usada sozinha ou como base para sobreposição com camisa aberta, jaqueta ou overshirt.</p><br/><br/><p data-start="1061" data-end="1085"><strong data-start="1061" data-end="1085">Estratégia de Venda:</strong></p><br/><br/><p data-start="1087" data-end="1366">Essa peça é a união do básico com o descolado. A estonagem entrega originalidade e atitude, enquanto o algodão puro garante conforto e durabilidade. Ideal para quem quer se vestir bem sem parecer montado. Destaque como <strong data-start="1306" data-end="1365">“a camiseta que carrega estilo próprio em cada lavagem”</strong>.</p><br/><br/>CÓDIGO DO PRODUTO<br/><br/>Ref: CR1222012', 0, 0, 39, 'https://classeafaria.com.br/wp-content/uploads/sites/7538/2025/08/Camiseta-estonada-stoned-Cor-Vinho.jpg', 0.6, 30.0, 20.0, 10.0, '82820-160', true);
INSERT INTO public.products (id, name, description, stock_quantity, price, category_id, image_url, weight, length, width, height, origin_zip, is_active) VALUES (gen_random_uuid(), 'Camisa Polo Premium Modal', 'A polo modal tem padronagem bicolor, com pontos sutis e elegância em sua combinação de cores.<br/><br/>Composição: 84% Modal e 16% Elastano.<br/><br/>CÓDIGO DO PRODUTO<br/><br/>Ref: 40910539657360', 0, 0, 41, 'https://classeafaria.com.br/wp-content/uploads/sites/7538/2025/08/POLO-MODAL-SALMON.jpg', 0.6, 30.0, 20.0, 10.0, '82820-160', true);
INSERT INTO public.products (id, name, description, stock_quantity, price, category_id, image_url, weight, length, width, height, origin_zip, is_active) VALUES (gen_random_uuid(), 'POLO BASIC CLASSE A', '<ul class="list-tabs"><br/><br/> 	<li class="tab-title">DESCRIÇÃO</li><br/><br/></ul><br/><br/><div class="wrapper-tab-content"><br/><br/><div id="collapse-tab1" class="tab-content active" data-tabcontent=""><br/><br/><div class="rte"><br/><br/>Polo piquet com elastano de qualidade superior, toque macio.<br/><br/>Modelagem Regular curta<br/><br/>Tecido em ALGODÃO SUTENTÁVEL CERTIFICADO pelo BCI.<br/><br/>Confortável para todos os momentos, é a base da sua marca.<br/><br/>Composição: 98% algodão 2% poliéster<br/><br/>CÓDIGO DO PRODUTO<br/><br/>Ref: 11010120111360<br/><br/></div><br/><br/></div><br/><br/></div>', 0, 0, 41, 'https://classeafaria.com.br/wp-content/uploads/sites/7538/2025/08/polo-azul.jpg', 0.6, 30.0, 20.0, 10.0, '82820-160', true);
INSERT INTO public.products (id, name, description, stock_quantity, price, category_id, image_url, weight, length, width, height, origin_zip, is_active) VALUES (gen_random_uuid(), 'POLO PIQUET MAQUINETADA " CLASSE A "', '<ul class="list-tabs"><br/><br/> 	<li class="tab-title">DESCRIÇÃO</li><br/><br/></ul><br/><br/><div class="wrapper-tab-content"><br/><br/><div id="collapse-tab1" class="tab-content active" data-tabcontent=""><br/><br/><div class="rte"><br/><br/><p data-pm-slice="1 1 []">A polo maquinetada tem padronagem com pontos sutis e elegância em sua combinação de fios.</p><br/><br/>A presença de viscose nessa peça dá um toque extremamente macio, caimento diferenciado e um leve brilho natural.<br/><br/>Composição: 49% Algodão, 49% Viscose e 2% Elastano<br/><br/>MODELAGEM: Polo<br/><br/>COMPOSIÇÃO: 49% Algodão, 49% Viscose e 2% Elastano<br/><br/>&nbsp;<br/><br/></div><br/><br/></div><br/><br/></div>', 0, 0, 41, 'https://classeafaria.com.br/wp-content/uploads/sites/7538/2025/08/POLO-BRANCA.png', 0.6, 30.0, 20.0, 10.0, '82820-160', true);
INSERT INTO public.products (id, name, description, stock_quantity, price, category_id, image_url, weight, length, width, height, origin_zip, is_active) VALUES (gen_random_uuid(), 'CAMISA SOCIAL FRANELA SLIM FIT', '<strong>Camisa Masculina Flanela Slim Fit </strong>—<br/><br/>Estilo, conforto e caimento impecável para todas as ocasiões<br/><br/>Uma peça essencial no guarda-roupa masculino, pensada para quem busca sofisticação com praticidade no dia a dia. Ideal para compor looks versáteis com elegância e conforto.<br/><br/><strong>Diferenciais Técnicos:</strong><br/><br/>Tecido 100% algodão com toque macio e confortável<br/><br/>Flanela de gramatura média: ideal para dias amenos<br/><br/>Modelagem slim fit que valoriza a silhueta masculina<br/><br/>Gola estruturada com acabamento refinado<br/><br/>Botões frontais e nos punhos para ajuste prático e estiloso<br/><br/>Costuras reforçadas que garantem durabilidade<br/><br/><strong>Usabilidade e Combinações:</strong><br/><br/>Ideal para composições casuais, urbanas ou de trabalho<br/><br/>Combina com calças jeans ou sarja<br/><br/>Pode ser usada sozinha ou como sobreposição com camiseta básica<br/><br/>Excelente opção para climas mais frescos sem abrir mão do estilo<br/><br/><strong>Estratégia de Venda:</strong><br/><br/>Produto com ótimo giro no segmento masculino, indicado tanto para o público jovem quanto adulto. Excelente aceitação em lojas que buscam oferecer peças atemporais, com toque moderno e acabamento de qualidade.', 0, 0, 37, 'https://classeafaria.com.br/wp-content/uploads/sites/7538/2025/08/Camisa-flanela-manga-longa-slim-fit-AZUL.jpg', 0.6, 30.0, 20.0, 10.0, '82820-160', true);
INSERT INTO public.products (id, name, description, stock_quantity, price, category_id, image_url, weight, length, width, height, origin_zip, is_active) VALUES (gen_random_uuid(), 'CAMISA SOCIAL SLIM FIT ALGODÃO EGÍPCIO', '&nbsp;<br/><br/>Descrição<br/><br/>Camisa manga longa modelagem SLIM FIT, levemente ajustada ao corpo e colarinho reforçado.<br/><br/>&nbsp;<br/><br/>Tecido em ALGODÃO EGÍPCIO, de fibra extra longa e toque inigualável.<br/><br/>&nbsp;<br/><br/>Exclusividade, requinte e qualidade premium que sua marca merece.<br/><br/>&nbsp;<br/><br/>Básica e para todos os estilos!<br/><br/>Composição: 100% Algodão Egípcio.', 0, 0, 37, 'https://classeafaria.com.br/wp-content/uploads/sites/7538/2025/08/Camisa-manga-longa-slim-fit-algodao-egipcio-PRETO.png', 0.6, 30.0, 20.0, 10.0, '82820-160', true);
INSERT INTO public.products (id, name, description, stock_quantity, price, category_id, image_url, weight, length, width, height, origin_zip, is_active) VALUES (gen_random_uuid(), 'CAMISA SOCIAL CONFORT BÁSICA', '&nbsp;<br/><br/><ul class="list-tabs"><br/><br/> 	<li><strong>DESCRIÇÃO</strong></li><br/><br/></ul><br/><br/><div class="wrapper-tab-content"><br/><br/><div id="collapse-tab1" class="tab-content active" data-tabcontent=""><br/><br/><div class="rte"><br/><br/>Camisa manga longa modelagem COMFORT FIT, mais reta e tradicional.<br/><br/>Com bolso ou sem, a escolha é sua!<br/><br/>Ideal para o dia a dia, no escritório ou para clientes básicos que preferem camisas mais soltas ao corpo.<br/><br/>cOMPOSIÇÃO: 100% algodão, fio 60.<br/><br/></div><br/><br/></div><br/><br/></div><br/><br/>&nbsp;', 0, 0, 37, 'https://classeafaria.com.br/wp-content/uploads/sites/7538/2025/08/Camisa-manga-longa-comfort-basica-PRETA.jpg', 0.6, 30.0, 20.0, 10.0, '82820-160', true);
INSERT INTO public.products (id, name, description, stock_quantity, price, category_id, image_url, weight, length, width, height, origin_zip, is_active) VALUES (gen_random_uuid(), 'CAMISA SOCIAL SLIM FIT BUTTON DOWN XADREZ', '&nbsp;<br/><br/><ul class="list-tabs"><br/><br/> 	<li><strong>DESCRIÇÃO</strong></li><br/><br/></ul><br/><br/><div class="wrapper-tab-content"><br/><br/><div id="collapse-tab1" class="tab-content active" data-tabcontent=""><br/><br/><div class="rte"></div><br/><br/></div><br/><br/></div><br/><br/><p data-pm-slice="1 1 []"><strong>CAMISA MANGA LONGA SLIM FIT BUTTON DOWN XADREZ</strong></p><br/><br/>Combinando estilo contemporâneo com versatilidade clássica, a Camisa Manga Longa Slim Fit Button Down Xadrez é ideal para quem valoriza elegância no dia a dia. Sua modelagem slim proporciona um caimento ajustado ao corpo, valorizando a silhueta masculina sem abrir mão do conforto.<br/><br/>Confeccionada em tecido leve e estruturado, essa peça é uma escolha certeira para composições modernas que transitam entre o casual e o social com naturalidade.<br/><br/><strong>Diferenciais Técnicos:</strong><br/><br/>Composição: 100% algodão fio 60 – leve, respirável e com toque superior.<br/><br/>Tecido confortável com estrutura leve e durável.<br/><br/>Modelagem slim fit – ajustada ao corpo com caimento elegante.<br/><br/>Gola button down – prática e alinhada, ideal para diversas ocasiões.<br/><br/>Estampa xadrez atemporal – confere personalidade ao look.<br/><br/>Punhos com botão – acabamento funcional e refinado.<br/><br/><strong>Usabilidade e Composições:</strong><br/><br/>Ideal para compromissos profissionais, jantares ou eventos informais.<br/><br/>Combina com jeans escuros ou alfaiataria.<br/><br/>Funciona bem sozinha ou sob sobreposição com blazer casual ou suéter.', 0, 0, 37, 'https://classeafaria.com.br/wp-content/uploads/sites/7538/2025/08/Camisa-manga-longa-slim-fit-button-down-xadrez-AZUL-CLARO-com-BRANCO.jpg', 0.6, 30.0, 20.0, 10.0, '82820-160', true);
INSERT INTO public.products (id, name, description, stock_quantity, price, category_id, image_url, weight, length, width, height, origin_zip, is_active) VALUES (gen_random_uuid(), 'CAMISA SOCIAL MANGA CURTA SLIM FIT LINHO', '&nbsp;<br/><br/><ul class="list-tabs"><br/><br/> 	<li><strong>DESCRIÇÃO</strong></li><br/><br/></ul><br/><br/><div class="wrapper-tab-content"><br/><br/><div id="collapse-tab1" class="tab-content active" data-tabcontent=""><br/><br/><div class="rte"><br/><br/><p dir="ltr">Camisa manga curta modelagem SLIM FIT, levemente ajustada ao corpo.</p><br/><br/><p dir="ltr">Tecido premium em cambraia de LINHO com algodão, fresco, natural e resistente.</p><br/><br/><p dir="ltr">Mistura de conforto, durabilidade e toque leve, é a peça ideal para se manter elegante mesmo em temperaturas mais altas.</p><br/><br/><p dir="ltr">Composição:</p><br/><br/><p dir="ltr">Natural: 55% Algodão, 30% VISCOSE, 15% Linho.</p><br/><br/><p dir="ltr">Demais cores: 55% Linho, 45% Algodão.</p><br/><br/></div><br/><br/></div><br/><br/></div><br/><br/>&nbsp;', 0, 0, 37, 'https://classeafaria.com.br/wp-content/uploads/sites/7538/2025/08/Camisa-manga-curta-slim-fit-linho-VERDE-MAR.png', 0.6, 30.0, 20.0, 10.0, '82820-160', true);
INSERT INTO public.products (id, name, description, stock_quantity, price, category_id, image_url, weight, length, width, height, origin_zip, is_active) VALUES (gen_random_uuid(), 'CAMISA SOCIAL MANGA CURTA SLIM FIT BÁSICA', '&nbsp;<br/><br/><ul class="list-tabs"><br/><br/> 	<li><strong>DESCRIÇÃO</strong></li><br/><br/></ul><br/><br/><div class="wrapper-tab-content"><br/><br/><div id="collapse-tab1" class="tab-content active" data-tabcontent=""><br/><br/><div class="rte"></div><br/><br/></div><br/><br/></div><br/><br/>Camisa manga curta modelagem SLIM FIT, levemente ajustada ao corpo.<br/><br/>Campeã de vendas, essa camisa é a base da sua marca e peça chave no armário de todo homem.<br/><br/>Composição: 100% Algodão', 0, 0, 37, 'https://classeafaria.com.br/wp-content/uploads/sites/7538/2025/08/Camisa-manga-curta-slim-fit-basica-PRETO.jpg', 0.6, 30.0, 20.0, 10.0, '82820-160', true);
INSERT INTO public.products (id, name, description, stock_quantity, price, category_id, image_url, weight, length, width, height, origin_zip, is_active) VALUES (gen_random_uuid(), 'Calça Alfaiataria Skinny Sarja com Elástano', '&nbsp;<br/><br/><ul class="list-tabs"><br/><br/> 	<li><strong>DESCRIÇÃO</strong></li><br/><br/></ul><br/><br/><div class="wrapper-tab-content"><br/><br/><div id="collapse-tab1" class="tab-content active" data-tabcontent=""><br/><br/><div class="rte"><br/><br/>SARJA PREMIUM com elastano, peletizada e com acabamento de cetim. Toque macio, levemente aveludado e com brilho natural.<br/><br/>SKINNY de bolso faca, acabamento interno de alfaiataria superior, forrado e com composição de tecidos no cós.<br/><br/>Calça de alto nível, essencial para compor qualquer look com estilo.<br/><br/>Composição: 98% algodão 2% elastano<br/><br/></div><br/><br/></div><br/><br/></div><br/><br/>&nbsp;', 0, 0, 40, 'https://classeafaria.com.br/wp-content/uploads/sites/7538/2025/08/Calca-alfaiataria-skinny-sarja-com-elastano-PRETO.jpg', 0.7, 30.0, 20.0, 10.0, '82820-160', true);
INSERT INTO public.products (id, name, description, stock_quantity, price, category_id, image_url, weight, length, width, height, origin_zip, is_active) VALUES (gen_random_uuid(), 'Blazer Slim Poliviscose', '&nbsp;<br/><br/><ul class="list-tabs"><br/><br/> 	<li><strong>DESCRIÇÃO</strong></li><br/><br/></ul><br/><br/><div class="wrapper-tab-content"><br/><br/><div id="collapse-tab1" class="tab-content active" data-tabcontent=""><br/><br/><div class="rte"></div><br/><br/></div><br/><br/></div><br/><br/><p data-pm-slice="1 1 []"><strong>BLAZER SLIM POLIVISCOSE</strong></p><br/><br/>O Blazer Slim Poliviscose é a escolha perfeita para homens que buscam sofisticação com um toque moderno. Confeccionado em tecido de alfaiataria com 80% poliéster e 20% viscose, oferece estrutura, conforto e caimento impecável. O forro 100% poliéster garante acabamento interno refinado, enquanto os detalhes como pesponto, abotoamentos e bolsos funcionais elevam a elegância da peça.<br/><br/><strong>Diferenciais Técnicos:</strong><br/><br/><ul data-spread="false"><br/><br/> 	<li>Tecido de poliviscose (80% poliéster, 20% viscose) com estrutura ideal para alfaiataria.</li><br/><br/> 	<li>Caimento slim que valoriza a silhueta masculina.</li><br/><br/> 	<li>Forro interno 100% poliéster para maior conforto e acabamento premium.</li><br/><br/> 	<li>Pespontos aparentes que reforçam o design refinado.</li><br/><br/> 	<li>Mangas longas com abotoamento nos punhos.</li><br/><br/> 	<li>Fechamento frontal com botões, bolsos externos e internos funcionais.</li><br/><br/> 	<li>Lapelas clássicas e duas aberturas traseiras para liberdade de movimento.</li><br/><br/></ul><br/><br/><strong>Usabilidade e Combinações:</strong><br/><br/><ul data-spread="false"><br/><br/> 	<li>Ideal para eventos formais como casamentos, formaturas e jantares especiais.</li><br/><br/> 	<li>Pode ser usado também em ambientes de trabalho ou combinado com jeans para um visual casual chic.</li><br/><br/> 	<li>Versátil, permite a criação de looks monocromáticos ou contrastantes com camisa branca, calça chino ou calça social.</li><br/><br/></ul>', 0, 0, 48, 'https://classeafaria.com.br/wp-content/uploads/sites/7538/2025/08/Blazer-slim-poliviscose-AZUL.jpg', 1.2, 30.0, 55.0, 10.0, '82820-160', true);
INSERT INTO public.products (id, name, description, stock_quantity, price, category_id, image_url, weight, length, width, height, origin_zip, is_active) VALUES (gen_random_uuid(), 'Blazer Slim Le Passage', '&nbsp;<br/><br/><ul class="list-tabs"><br/><br/> 	<li><strong>DESCRIÇÃO</strong></li><br/><br/></ul><br/><br/><div class="wrapper-tab-content"></div><br/><br/><ul data-spread="false"><br/><br/> 	<li>LE PASSAGEBlazer Slim Casual<br/><br/>Corte Italiano<br/><br/>2 Botões Centrais<br/><br/>4 Botões na Manga<br/><br/>Tecido de Sarja, Durabilidade, Conforto e Muuuuita Elegância.Blazer extremamente confortável, peça dinâmica e autêntica.<br/><br/>Sarja transmite uma sensação de empoderamento e de respeito em todas as ocasiões, vista com camisas sociais e com camisas básicas lisas.</li><br/><br/></ul>', 0, 0, 50, 'https://classeafaria.com.br/wp-content/uploads/sites/7538/2025/08/BLAZER-SARJA-CINZA.jpg', 1.2, 30.0, 55.0, 12.0, '82820-160', true);
