INSERT INTO public.products (id, name, description, stock_quantity, price, category_id, image_url, weight, length, width, height, origin_zip, is_active) VALUES (gen_random_uuid(), 'Camisa Slim Branca Xadrez', '<strong>Descrição do produto</strong><br/><br/><div class="wrapper-tab-content"><br/><br/><div id="collapse-tab1" class="tab-content active" data-tabcontent=""><br/><br/><div class="rte"><br/><br/><div class="content"><br/><br/>Camisa Slim Social Branca Xadrez -<br/><br/>A camisa slim social branca xadrez é uma alternativa para quem prefere sair do básico para algo mais ousado. Com modelagem ajustada que valoriza a silhueta masculina, é perfeita para o homem moderno que busca sofisticação em cada detalhe. Feita com tecidos de alta qualidade, proporciona conforto e estilo, seja em um evento formal ou em um ambiente corporativo. O design clássico e versátil permite combinações com ternos ou até looks mais descontraídos. Invista em uma peça essencial no guarda-roupa de qualquer homem.<br/><br/>&nbsp;<br/><br/>✅ Design moderno: para você se destacar em todas as ocasiões;<br/><br/>✅Materiais de alta qualidade e duradouros;<br/><br/>✅ Acabamentos que fazem a diferença;<br/><br/></div><br/><br/></div><br/><br/></div><br/><br/></div>', 0, 0, 37, 'https://classeafaria.com.br/wp-content/uploads/sites/7538/2025/08/Camisa-Slim-Branca-Xadrez.jpg', 0.7, 30.0, 20.0, 10.0, '82820-160', true);
